#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int n,k[N],l[N],r[N],vis[N];
void dfs(int u)
{
	cout<<u<<" ";
	if(l[u]) dfs(l[u]);
	if(r[u]) dfs(r[u]);
}
stack<int> st;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		int x;
		cin>>x;
		k[x]=i;
	}
	for(int i=1;i<=n;i++)
	{
		bool flag=0;
		int lst;
		while(!st.empty()&&k[st.top()]>k[i])
		{
			lst=st.top();
			st.pop();
			flag=1;
		}
		if(!st.empty()) r[st.top()]=i;
		if(flag) l[i]=lst;
		st.push(i);
	}
	for(int i=1;i<=n;i++)
	{
		vis[l[i]]=vis[r[i]]=1;
	}
	for(int i=1;i<=n;i++)
	{
		if(vis[i]==0)
		{
			dfs(i);
			break;
		}
	}
	return 0;
}
